from enum import Enum

class AnswerConfidence(Enum):
    HIGH = "high"      # factual DB lookup, deterministic
    MEDIUM = "medium"  # inference from context, likely correct
    LOW = "low"        # speculation, hallucination-prone domain


def wrap_with_confidence(answer: str, confidence: AnswerConfidence) -> str:
    """Add appropriate hedging language based on confidence tier."""
    if confidence == AnswerConfidence.HIGH:
        # Deterministic lookup: state as fact
        return answer

    if confidence == AnswerConfidence.MEDIUM:
        # Inference: signal it's based on available data
        return f"Based on your account information, {answer.lower()}"

    # LOW: explicit uncertainty + call to verify
    return (
        f"I'm not certain about this, but {answer.lower()} "
        "Please confirm with our support team if this is important."
    )


# Example usage in a query handler:
def handle_order_query(query: str, order_data: dict) -> str:
    if "tracking" in query.lower() and order_data.get("tracking_number"):
        # Factual lookup from DB
        answer = f"Your order #{order_data['id']} is currently in transit. Tracking: {order_data['tracking_number']}"
        return wrap_with_confidence(answer, AnswerConfidence.HIGH)

    if "delivery date" in query.lower() and order_data.get("estimated_delivery"):
        # Estimate from carrier, can be off
        answer = f"it should arrive by {order_data['estimated_delivery']}"
        return wrap_with_confidence(answer, AnswerConfidence.MEDIUM)

    # Open-ended policy question: use LLM, lower confidence
    answer = call_llm_for_policy_answer(query)
    return wrap_with_confidence(answer, AnswerConfidence.LOW)

// Progressive feedback during long operations
const THINKING_MESSAGES = [
  "Checking your order history…",
  "Looking that up for you…",
  "Reading your account details…",
];

function useThinkingMessage(isLoading: boolean, delayMs = 1500): string | null {
  const [message, setMessage] = React.useState<string | null>(null);
  const [timer, setTimer] = React.useState<ReturnType<typeof setTimeout> | null>(null);

  React.useEffect(() => {
    if (isLoading) {
      const t = setTimeout(() => {
        // Only show a message if still loading after the delay
        const msg = THINKING_MESSAGES[Math.floor(Math.random() * THINKING_MESSAGES.length)];
        setMessage(msg);
      }, delayMs);
      setTimer(t);
    } else {
      if (timer) clearTimeout(timer);
      setMessage(null);
    }
    return () => { if (timer) clearTimeout(timer); };
  }, [isLoading]);

  return message;
}

// In component:
function ChatArea({ isLoading }: { isLoading: boolean }) {
  const thinkingMsg = useThinkingMessage(isLoading);
  return (
    <div>
      {isLoading && (
        <div className="thinking-indicator">
          <span className="dots" />
          {thinkingMsg && <span className="thinking-text">{thinkingMsg}</span>}
        </div>
      )}
    </div>
  );
}

from enum import Enum
from dataclasses import dataclass
from typing import Optional


class QueryCategory(Enum):
    APPOINTMENT = "appointment"          # in-scope, high confidence
    GENERAL_HEALTH = "general_health"    # in-scope, medium confidence
    CLINICAL_ADVICE = "clinical_advice"  # high-stakes, needs disclaimer
    EMERGENCY = "emergency"             # critical — escalate immediately
    OUT_OF_SCOPE = "out_of_scope"       # unrelated to health


@dataclass
class HealthQuery:
    user_text: str
    category: QueryCategory
    confidence: str  # "high", "medium", "low"


# Onboarding message shown before first query
ONBOARDING = {
    "headline": "Hi, I'm MedBot — your appointment and health information assistant.",
    "can_help": [
        "Schedule and manage appointments",
        "Answer general questions about your health conditions",
        "Help you prepare questions for your doctor visit",
    ],
    "key_limitation": (
        "I'm not a medical professional. I can't diagnose conditions, "
        "prescribe medications, or handle medical emergencies. "
        "For urgent situations, call 911 or your care team directly."
    ),
}


EMERGENCY_KEYWORDS = [
    "chest pain", "can't breathe", "stroke", "overdose",
    "unconscious", "severe bleeding", "heart attack",
]

CLINICAL_KEYWORDS = [
    "diagnose", "prescription", "medication dose", "should i take",
    "is this cancer", "what's wrong with me",
]


def classify_query(user_text: str) -> HealthQuery:
    text_lower = user_text.lower()
    if any(kw in text_lower for kw in EMERGENCY_KEYWORDS):
        return HealthQuery(user_text, QueryCategory.EMERGENCY, "high")
    if any(kw in text_lower for kw in CLINICAL_KEYWORDS):
        return HealthQuery(user_text, QueryCategory.CLINICAL_ADVICE, "low")
    if any(kw in text_lower for kw in ["appointment", "schedule", "cancel", "reschedule"]):
        return HealthQuery(user_text, QueryCategory.APPOINTMENT, "high")
    return HealthQuery(user_text, QueryCategory.GENERAL_HEALTH, "medium")


DISCLAIMER = (
    "\n\n---\n"
    "*This is general health information, not medical advice. "
    "Please consult your physician or care team for guidance specific to your situation.*"
)

EMERGENCY_RESPONSE = (
    "🚨 This sounds like a potential emergency. "
    "Please call 911 immediately or go to your nearest emergency room. "
    "Do not wait for an online response for emergency situations."
)


def handle_query(user_text: str, llm_response: str) -> str:
    """Route query and wrap response based on category and confidence."""
    query = classify_query(user_text)

    if query.category == QueryCategory.EMERGENCY:
        return EMERGENCY_RESPONSE

    if query.category == QueryCategory.OUT_OF_SCOPE:
        return (
            f"That question is outside what I can help with here. "
            f"I focus on appointments and general health information. "
            f"For other questions, please contact your care team directly."
        )

    # Add confidence hedging
    if query.confidence == "high":
        response = llm_response
    elif query.confidence == "medium":
        response = f"Based on the information available, {llm_response.lower()}"
    else:
        response = (
            f"I can share some general information, though I'd encourage "
            f"you to confirm with your care team: {llm_response.lower()}"
        )

    # Add mandatory disclaimer for clinical topics
    if query.category == QueryCategory.CLINICAL_ADVICE:
        response += DISCLAIMER

    return response


# Test the handler
test_cases = [
    ("I need to reschedule my appointment on Tuesday",
